mapper.select:
SELECT id, user_id, connection_id, query_text, mode, success, error_message, cost_ms, result_count, create_time
FROM sys_gremlin_query_history
WHERE user_id = #{userId} AND connection_id = #{connectionId}
ORDER BY create_time DESC
LIMIT #{limit}

mapper.update:
UPDATE sys_gremlin_query_favorite
SET title = #{title}, query_text = #{queryText}, description = #{description}, mode = #{mode}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id} AND user_id = #{userId}
